#!/bin/sh
# Pivot the residential proxy from uhttpd-CGI to Node (x86_64 OpenWRT).
set -e
echo '[1/5] installing node...'
apk add node || apk add nodejs || { echo 'ERROR: no node package found; run: apk search node'; exit 1; }
node --version

echo '[2/5] stopping the old CGI proxy...'
/etc/init.d/suxproxy stop 2>/dev/null || true

echo '[3/5] writing server.mjs...'
mkdir -p /srv/suxproxy
cat > /srv/suxproxy/server.b64 <<'B64_EOF'

B64_EOF
base64 -d /srv/suxproxy/server.b64 > /srv/suxproxy/server.mjs
rm -f /srv/suxproxy/server.b64

echo '[4/5] writing init (node + PROXY_SECRET)...'
cat > /etc/init.d/suxproxy <<'INIT_EOF'
#!/bin/sh /etc/rc.common
START=95
USE_PROCD=1
start_service() {
	procd_open_instance
	procd_set_param command /usr/bin/node /srv/suxproxy/server.mjs
	procd_set_param env PROXY_SECRET="${PROXY_SECRET:?run this provisioner with PROXY_SECRET set in the environment}"
	procd_set_param respawn
	procd_close_instance
}
INIT_EOF
chmod +x /etc/init.d/suxproxy
/etc/init.d/suxproxy enable
/etc/init.d/suxproxy restart
sleep 1

echo '[5/5] signed self-test (expect status:200 + ip= in body):'
TS=1
BODY='{"url":"https://cloudflare.com/cdn-cgi/trace"}'
SIG=$(printf '%s\n%s' "$TS" "$BODY" | openssl dgst -sha256 -hmac "$PROXY_SECRET" -r | cut -d' ' -f1)
curl -s -X POST http://127.0.0.1:8787/fetch \
  -H "x-timestamp: $TS" \
  -H "x-signature: $SIG" \
  -H 'content-type: application/json' \
  --data "$BODY"
echo
